-- в”Ђв”Ђ Seriously Simple Podcasting в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Free WordPress plugin by Castos that lets any WordPress site publish, manage, and distribute a podcast with an Apple- and Spotify-compliant RSS feed.$q$, short_description),
  pricing_model = COALESCE($q$Free WordPress plugin; optional paid podcast hosting available separately$q$, pricing_model),
  starting_price = COALESCE($q$Free (optional Castos hosting from $19/month)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Seriously Simple Podcasting Review 2026: Free WordPress Podcast Plugin$q$, seo_title),
  seo_meta_description = COALESCE($q$Seriously Simple Podcasting is a free WordPress plugin for publishing podcasts. See 2026 features, RSS feed setup, pros and cons, and optional hosting pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Seriously Simple Podcasting is a free WordPress plugin that turns any WordPress website into a fully functional podcast host and publishing tool. It is developed and maintained by Castos, a podcast hosting company founded in 2015 by Craig Hewitt, though the plugin itself is free to use regardless of where audio or video files are actually hosted. According to its WordPress.org listing, Seriously Simple Podcasting powers more than 30,000 active podcast installations and is used to generate RSS feeds that comply with the technical requirements of Apple Podcasts, Spotify, Amazon Music, and virtually every other podcast directory and listening app. The plugin adds a dedicated Podcast post type to WordPress, letting users create and manage episodes alongside their regular posts and pages, attach audio or video files, add show notes, and embed a built-in audio or video player on the site. Setup is designed to be completed in a handful of steps, from installing the plugin to submitting a working RSS feed to podcast directories. Because Seriously Simple Podcasting is hosting-agnostic, users can store media files on their own server, on generic cloud storage, or on a dedicated podcast hosting provider; Castos is the natural upsell path, with paid hosting plans starting at $19 per month for the Essentials tier and scaling to $49 for Growth, $99 for Pro, and custom Premium pricing starting at $499 per month for large organizations. A free companion add-on, Seriously Simple Stats, adds listener analytics including total listens per episode, filtering by date range, and breakdowns by listening source. The plugin remains free to use indefinitely regardless of whether a paid Castos plan is ever purchased.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '88430172-33f0-425e-bfc6-d920de02220c';

